<?php
 namespace WPAICG\Vector\ManagerMethods; use WPAICG\Vector\AIPKit_Vector_Provider_Strategy_Interface; use WPAICG\Vector\AIPKit_Vector_Provider_Strategy_Factory; use WP_Error; if (!defined('ABSPATH')) { exit; } function get_connected_strategy_logic(string $provider, array $provider_config): AIPKit_Vector_Provider_Strategy_Interface|WP_Error { if (!class_exists(AIPKit_Vector_Provider_Strategy_Factory::class)) { return new WP_Error('factory_missing', __('Vector Provider Strategy Factory is not available.', 'gpt3-ai-content-generator')); } $strategy = AIPKit_Vector_Provider_Strategy_Factory::get_strategy($provider); if (is_wp_error($strategy)) { return $strategy; } $connect_result = $strategy->connect($provider_config); if (is_wp_error($connect_result) || $connect_result === false) { return is_wp_error($connect_result) ? $connect_result : new WP_Error('connection_failed', sprintf(__('Failed to connect to %s vector store.', 'gpt3-ai-content-generator'), $provider)); } return $strategy; }